// Hook : online sync via Socket.IO /game (best-effort, doesn't block UI)
function useGameSocket(roomCode: string | undefined, onState: (s: any) => void) {
  const socketRef = useRef<Socket | null>(null);
  const [connected, setConnected] = useState(false);
  useEffect(() => {
    if (!roomCode) return;
    const s = io(`${SOCKET_URL}/game`, { transports: ['websocket'], timeout: 4000 });
    socketRef.current = s;
    s.on('connect', () => {
      setConnected(true);
      log.bin(`socket /game connected → join room:${roomCode}`);
      s.emit('game:join', { roomCode });
    });
    s.on('game:state', (snapshot: any) => {
      log.bout('game:state received', { phase: snapshot?.phase });
      onState(snapshot);
    });
    s.on('disconnect', () => setConnected(false));
    s.on('connect_error', (e: any) => log.warn('socket connect_error', e?.message));
    return () => { s.disconnect(); socketRef.current = null; };
  }, [roomCode]);
  const emitMove = useCallback((action: any) => {
    socketRef.current?.emit('game:action', { roomCode, action });
  }, [roomCode]);
  return { connected, emitMove };
}

const HELP_TEXT = "Check, Call, Raise ou Fold. Meilleure main de 5 cartes au showdown.";
const FEEDBACK_CAPTURE = "💰 Pot remporté";
const FEEDBACK_SPECIAL = "♠ Quinte !";

export default function GameScreen() {
  const { roomCode } = useLocalSearchParams<{ roomCode: string }>();
  const router = useRouter();
  const { t } = useTranslation();
  const { palette } = useTheme();

  const [state, dispatch] = useReducer(Engine.gameReducer as any, undefined, () => {
    let s: any = (Engine as any).initGame();
    const players = [
      { id: ME,  name: 'Vous',  isBot: false },
      { id: 'b1', name: 'Bot 1', isBot: true },
      { id: 'b2', name: 'Bot 2', isBot: true },
    ];
    for (const p of players) s = Engine.gameReducer(s, { type: 'JOIN', playerId: p.id, playerName: p.name, isBot: p.isBot } as any);
    s = Engine.gameReducer(s, { type: 'START_GAME' } as any);
    return s;
  });

  const [moveLog, setMoveLog] = useState<any[]>([]);
  const [toast, setToast] = useState<{ msg: string; color: string; key: number } | null>(null);
  const [showQuit, setShowQuit] = useState(false);
  const [betAmount, setBetAmount] = useState(50);
  const winner = (Engine as any).getWinner ? (Engine as any).getWinner(state) : null;
  const current = (Engine as any).getCurrentPlayer ? (Engine as any).getCurrentPlayer(state) : null;
  const isMyTurn = current?.id === ME && !winner;

  const { connected, emitMove } = useGameSocket(roomCode as any, (snap) => {
    if (snap) dispatch({ type: 'SYNC_FROM_SERVER', state: snap } as any);
  });

  // Win haptic + toast — séparé pour éviter de re-tirer Date.now() à chaque
  // render (cause de "Maximum update depth exceeded" si state change boucle).
  useEffect(() => {
    if (!winner) return;
    Haptics.notificationAsync(Haptics.NotificationFeedbackType.Success).catch(() => {});
    setToast({ msg: FEEDBACK_CAPTURE, color: '#10B981', key: Date.now() });
  }, [winner]);

  // Bot auto-play — deps minimales (current?.id et winner) pour éviter le
  // re-trigger à chaque dispatch. La fermeture lit `state` via stateRef.
  const stateRef = useRef(state);
  stateRef.current = state;
  useEffect(() => {
    if (winner) return;
    if (!current?.isBot || !(Engine as any).botPlay) return;
    const timer = setTimeout(() => {
      const action = (Engine as any).botPlay(stateRef.current);
      if (action) {
        dispatch(action);
        emitMove(action);
        setMoveLog(l => [...l, { icon: '🤖', who: current.name, what: action.type.toLowerCase() }]);
      }
    }, BOT_THINK_MS);
    return () => clearTimeout(timer);
  }, [current?.id, winner, emitMove]);

  const me = state.players?.find((p: any) => p.id === ME);
  const community = state.communityCards ?? [];
  const pot = state.pot ?? 0;

  const doAction = (type: string, extra: any = {}) => {
    if (!isMyTurn) return;
    Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light).catch(() => {});
    const action = { type, playerId: ME, ...extra } as any;
    dispatch(action);
    emitMove(action);
    setMoveLog(l => [...l, { icon: '👤', who: 'Vous', what: type.toLowerCase() }]);
  };

  const restart = () => {
    let s: any = (Engine as any).initGame();
    for (const p of [{ id: ME, name: 'Vous', isBot: false }, { id: 'b1', name: 'Bot 1', isBot: true }, { id: 'b2', name: 'Bot 2', isBot: true }]) {
      s = Engine.gameReducer(s, { type: 'JOIN', playerId: p.id, playerName: p.name, isBot: p.isBot } as any);
    }
    s = Engine.gameReducer(s, { type: 'START_GAME' } as any);
    dispatch({ type: 'SYNC_FROM_SERVER', state: s } as any);
    setMoveLog([]);
  };

  return (
    <View style={[localStyles.root, { backgroundColor: palette.bg }]}>
      <LinearGradient colors={palette.bgGradient} style={StyleSheet.absoluteFill} />
      <AppHeader title={APP_CONFIG.name} subtitle={`Salon ${roomCode ?? '—'} ${connected ? '· 🟢' : '· 🔌'}`} showBack onBack={() => setShowQuit(true)} />

      <ScrollView contentContainerStyle={localStyles.body}>
        <AvatarRow players={state.players} currentId={current?.id} palette={palette} />
        <PhaseBanner phase={state.phase} current={current} isMyTurn={isMyTurn} winner={winner} palette={palette} />
        <HelpChip palette={palette} text={HELP_TEXT} />

        {/* Pot + Phase */}
        <LinearGradient colors={['rgba(239,68,68,0.18)', palette.card]} style={[localStyles.potBox, { borderColor: palette.border }]}>
          <View style={{ flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center' }}>
            <View>
              <Text style={[localStyles.sectionLabel, { color: palette.text }]}>💰 Pot</Text>
              <Text style={[localStyles.potValue, { color: APP_CONFIG.primary }]}>{pot}</Text>
            </View>
            <View style={{ alignItems: 'flex-end' }}>
              <Text style={{ color: palette.textSecondary, fontSize: 11, fontFamily: 'Inter-Bold' }}>VOS JETONS</Text>
              <Text style={[localStyles.potValue, { color: palette.text }]}>{me?.chips ?? 0}</Text>
            </View>
          </View>
        </LinearGradient>

        {/* Community cards */}
        <Text style={[localStyles.handTitle, { color: palette.text }]}>🃏 Cartes communes ({community.length}/5)</Text>
        <View style={localStyles.communityRow}>
          {Array.from({ length: 5 }).map((_, i) => {
            const c = community[i];
            return c ? (
              <AnimatedCard key={i} value={String(c.value)} suit={c.suit} width={50} height={72} facing="up" />
            ) : (
              <View key={i} style={[localStyles.placeholderSlot, { borderColor: palette.border }]}>
                <Text style={{ color: palette.textSecondary, fontSize: 18 }}>?</Text>
              </View>
            );
          })}
        </View>

        {/* Hole cards */}
        <Text style={[localStyles.handTitle, { color: palette.text, marginTop: 16 }]}>👁 Vos cartes</Text>
        <View style={localStyles.handScroll}>
          {(me?.hand ?? []).map((c: any) => (
            <AnimatedCard key={c.id} value={String(c.value)} suit={c.suit} width={70} height={102} facing="up" />
          ))}
        </View>

        <MoveLog entries={moveLog} palette={palette} />

        {/* Actions */}
        {isMyTurn && (
          <View style={localStyles.actionsGrid}>
            <TouchableOpacity style={[localStyles.actionBtn, { backgroundColor: '#10B981' }]} onPress={() => doAction('CHECK')}>
              <Ionicons name="checkmark" size={18} color="#fff" />
              <Text style={localStyles.actionText}>Check</Text>
            </TouchableOpacity>
            <TouchableOpacity style={[localStyles.actionBtn, { backgroundColor: '#3B82F6' }]} onPress={() => doAction('CALL')}>
              <Ionicons name="arrow-redo" size={18} color="#fff" />
              <Text style={localStyles.actionText}>Call</Text>
            </TouchableOpacity>
            <TouchableOpacity style={[localStyles.actionBtn, { backgroundColor: APP_CONFIG.primary }]} onPress={() => doAction('RAISE', { amount: betAmount })}>
              <Ionicons name="trending-up" size={18} color="#fff" />
              <Text style={localStyles.actionText}>Raise +{betAmount}</Text>
            </TouchableOpacity>
            <TouchableOpacity style={[localStyles.actionBtn, { backgroundColor: '#EF4444' }]} onPress={() => doAction('FOLD')}>
              <Ionicons name="close" size={18} color="#fff" />
              <Text style={localStyles.actionText}>Fold</Text>
            </TouchableOpacity>
          </View>
        )}

        {/* Bet slider — quick presets */}
        {isMyTurn && (
          <View style={localStyles.betPresets}>
            {[20, 50, 100, 200].map(v => (
              <TouchableOpacity
                key={v}
                onPress={() => setBetAmount(v)}
                style={[localStyles.betPreset, { borderColor: betAmount === v ? APP_CONFIG.primary : palette.border, backgroundColor: betAmount === v ? APP_CONFIG.primary + '33' : 'rgba(255,255,255,0.04)' }]}
              >
                <Text style={[localStyles.betPresetText, { color: palette.text }]}>{v}</Text>
              </TouchableOpacity>
            ))}
          </View>
        )}
      </ScrollView>

      <FeedbackToast message={toast?.msg} visible={!!toast} color={toast?.color} key={toast?.key} />
      <WinnerModal visible={!!winner} winner={winner} onAgain={restart} onQuit={() => router.back()} palette={palette} />

      <Modal visible={showQuit} transparent animationType="fade">
        <View style={styles.modalBackdrop}>
          <View style={[styles.modalCard, { backgroundColor: palette.card, borderColor: palette.border }]}>
            <Text style={styles.modalTitle}>Quitter la partie ?</Text>
            <View style={{ flexDirection: 'row', gap: 12, marginTop: 18 }}>
              <TouchableOpacity onPress={() => setShowQuit(false)} style={[styles.modalBtn, { backgroundColor: 'rgba(255,255,255,0.15)' }]}><Text style={styles.modalBtnText}>Annuler</Text></TouchableOpacity>
              <TouchableOpacity onPress={() => { setShowQuit(false); router.back(); }} style={[styles.modalBtn, { backgroundColor: '#EF4444' }]}><Text style={styles.modalBtnText}>Quitter</Text></TouchableOpacity>
            </View>
          </View>
        </View>
      </Modal>
    </View>
  );
}

